var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"칫, 쇳덩어리가 왜 이렇게 가벼워? 힘을 주기도 전에 날아가버리잖아.","JPN":"チッ、鉄の塊のくせになんて軽いんだ？　まだ力も入れてないのにぶっ飛んだじゃないか。","ENG":"Hmph, that was light for a chunk of metal. It flew away even before I put in my full strength.","TWN":"嘖，不是鐵做的嗎？怎麼這麼輕？我拳頭都還沒碰到欸，他怎麼就先飛出去？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"뭐야? 저 깡패…? 왜 저리 무식하게 세?","JPN":"何？　あのチンピラ……？　なんて力なの？","ENG":"What is she? A gangster or what...? Why is she so strong?","TWN":"哇賽？那個女流氓…？頭腦簡單四肢也太發達？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"이… 이럴 수가. 어떻게 이런 일이.","JPN":"こ、こんなことが……ありえるのか？","ENG":"Oh... Oh my. How can this happen?","TWN":"這…怎麼可能？怎麼會有這種事？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"난 경고했어. 변상하라고 했다간 다음은 너야.","JPN":"アタシは警告した。弁償しろとか言ったら、次はお前の番だ。","ENG":"I warned you. If you tell me to pay for the damage, you’re going to be next.","TWN":"我剛有事先警告過囉，要是敢叫我賠償下一個挨揍的就是你！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"당신… 이름이 뭐죠?","JPN":"あなた……お名前は？","ENG":"You... What’s your name?","TWN":"你…叫什麼名字？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"알아서 뭐하게?","JPN":"知ってどうする。","ENG":"What do you need my name for?","TWN":"知道我的名字要幹嘛？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"그 차갑고 무신경한 태도. 역시 닮았어.","JPN":"その冷たくて無神経な態度。やっぱりそうだ。","ENG":"That cold, indifferent attitude. I knew it!","TWN":"那副傲嬌又粗線條的態度，完全一模一樣！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"당신은 내가 줄곧 생각해왔던 파벨라와 똑같아!","JPN":"あなたは私がずっと思い描いてたファヴェーラとそっくりだ！","ENG":"You’re the Fabella I’ve been looking for!","TWN":"你就是我一直在尋尋覓覓的帕貝拉！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"윽…?!","JPN":"うっ……！？","ENG":"Ngh...?!","TWN":"蛤…？！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"오빠, 이 녀석 맘에 안 드는데. 두들겨 패도 돼?","JPN":"兄さん、こいつ気に入らないんだけど、殴っていいか？","ENG":"Doma, I don’t like him. Can I beat him up?","TWN":"哥，我不喜歡這傢伙，可以開扁嗎？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"참아보렴, 동생아. 지금 감독님이 실려가면 의뢰인 분께서 곤란해지거든.","JPN":"我慢しなさい、妹よ。今監督が病院行きになったら、依頼人が困るから。","ENG":"Hold it, my sister. Our client will be in trouble if the director ends up in the hospital.","TWN":"妹妹，你先忍忍。萬一導演現在送急診的話，委託人會很困擾的。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"자네! 드라마 주인공에 도전해볼 생각 없나?","JPN":"君！　ドラマの主役に挑戦してみる気はないか？","ENG":"You! Don’t you want to be the lead of a TV series?","TWN":"我說你！你難道不想挑戰看看當連續劇女主角嗎？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"뭐어…?!","JPN":"はあ……！？","ENG":"What...?!","TWN":"什麼…？！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"아니, 관심 없는데.","JPN":"いや、興味ない。","ENG":"Nope, not interested.","TWN":"不想，沒興趣。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"당연히 거절 못 하겠지! 그럼 어서 계약 절차를…!","JPN":"当然断れないだろう！　じゃあ、早速契約の手続きを……！","ENG":"Of course you’ll take the offer! Then let’s hurry with the contract...!","TWN":"我就知道你是不會拒絕的！那來簽合…！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"…응? 관심 없다고?","JPN":"……えっ？　興味ない？","ENG":"...Huh? You’re not interested?","TWN":"…你說什麼？沒興趣？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"잠깐. 이게 어떤 자리인지 알긴 하고 말하는 거야?","JPN":"待て。これがどんな役かわかってはいるのか？","ENG":"Wait. Do you even know what kind of position this is?","TWN":"這麼好的機會，你知道你在說什麼嗎？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"내 작품의 주인공이 되는 순간, 온 연예계와 광고 스폰서들이 당신을 주목할 거라고!","JPN":"私の作品の主人公になれば、芸能界とスポンサーの注目を集めるのは造作もないはずだ！","ENG":"If you become the lead of my work, you’ll attract attention from the entire entertainment industry!","TWN":"只要你成為我戲裡的女主角，整個演藝圈和贊助商就會立刻關注你！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"그게 뭐가 좋은 건데?","JPN":"それのなにがいいんだ？","ENG":"What’s so good about that?","TWN":"那有什麼好的？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"어차피 재미없는 연기만 하루종일 연습해야 하는 거잖아? 귀찮아.","JPN":"どうせ一日中つまらない演技ばっかり練習しないといけないんだろう？　面倒くさい。","ENG":"Acting’s not fun, and I’ll have to practice it all day long. So bothersome.","TWN":"那不就整天都只能練習無聊的演戲？我不喜歡。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"알고 있었던 거니? 난 네가 드라마를 사실이라고 믿는 줄 알았단다.","JPN":"知っていたのか？　私はユマがドラマを本当だと信じているのかと思ったよ。","ENG":"You actually knew that TV series weren’t real? I thought you saw them as real stories.","TWN":"你知道是在演戲？我還以為你把連續劇都當成真的。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"사실이라고 믿을 때도 있었지. 프레데리카가 달로 여행을 떠나기 전까진 말이야.","JPN":"本当だって信じてた時期もあったな。フレデリカが月に旅立つまでは。","ENG":"I believed the stories were true until Frederica left to the moon.","TWN":"在弗蕾德莉卡到月球去旅行之前，我都以為是真的！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"달 착륙이라니. 인간이 달까지 가는 일이 진짜 가능할 리 없잖아?","JPN":"月に着陸って？　大体、人間が本当に月まで行けるわけないだろう？","ENG":"The moon? There’s no way a human can actually land on the moon.","TWN":"竟然登陸月球？人類怎麼可能登陸月球？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"음?","JPN":"うむ？","ENG":"Hmm?","TWN":"啥？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"그랬으면 마법사 놈들이 진작 달을 때려 부수고 늑대인간들을 말살시켰을 거라고.","JPN":"だったら魔法使いのやつらがとっくに月を破壊して、ライカンスロープを抹殺したはずだ。","ENG":"If so, the wizards would have bashed the moon and wiped out all the lycanthropes.","TWN":"要是這樣，魔法師早就毀掉月亮讓狼人絕種啦！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"뭐라고? 방금 늑대인간이라고 한 건가?","JPN":"何？　今ライカンスロープって言ったか？","ENG":"What was that? Did you just say lycanthrope?","TWN":"什麼？你剛說狼人？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"…아차!","JPN":"……しまった！","ENG":"...Uh-oh.","TWN":"…糟糕！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"완벽해! 자기 혼자만의 공상에 빠져 있는 데다 상식이 부족한 것마저 파벨라와 똑같이 닮았어!","JPN":"完璧だ！　自分の空想にハマっていて、さらに常識も足りないところまでファヴェーラそっくりだよ！","ENG":"Perfect! She’s daydreaming, and she lacks common sense. Exactly like Fabella!","TWN":"簡直完美！連沉浸在自己的小宇宙裡又沒常識，這一點也跟帕貝拉一模一樣！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"잠깐… 파벨라가 그런 캐릭터였어?","JPN":"ちょっと……ファヴェーラってそんなキャラクターだったの？","ENG":"Wait a second... Fabella was that kind of character?","TWN":"等一下…帕貝拉的人設是這樣喔？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"흐음, 유마 녀석 같은 성격을 가진 여주인공이라니. 제법 흥미롭긴 하구나.","JPN":"ふむ、ユマのような性格の主人公とは。なかなか興味深いのう。","ENG":"Hmm, a female lead with Yuma’s characteristics. Sounds interesting.","TWN":"嗯哼，女主角的個性竟然跟游馬一樣，感覺蠻有趣的呢。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"뭔데요, 그게! 저런 무식한 깡패가 주인공에 어울린다니. 그런 건 로맨스가 아니잖아요!","JPN":"なんですか、それ！　あんな単細胞なチンピラが主人公に適してるなんて。そんなのロマンスじゃないです！","ENG":"That’s nonsense! That kind of idiotic gangster won’t fit the lead. That’s not romance!","TWN":"什麼嘛！那種頭腦簡單四肢發達的流氓竟然要演主角，根本一點都不浪漫！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"바로 그거야! 유혹의 함교 열 한번째 시즌의 핵심 장르는 스페이스 오페라니까!","JPN":"それだ！　誘惑の艦橋11番目のシーズンの核心ジャンルはスペースオペラだからな！","ENG":"That’s it! The main genre of the eleventh season of The Bridge of Seduction is space opera!","TWN":"完全正確！誘惑的艦橋第11季是走科幻路線！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"그러니 당신! 부디 내 작품에서 연기해줘요. 이쪽이 얼마든지 맞춰주지!","JPN":"だから君！　どうか私の作品で演技してくれ。いくらでもこっちが合わせるから！","ENG":"So please! Act for me. I’ll do whatever you ask me to.","TWN":"所以！拜託你一定要來演！我們會完全配合你！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"칫.","JPN":"チッ。","ENG":"Hmpf.","TWN":"嘖！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"연기라는 건 각본대로만 하고, 내 마음대로 할 수 있는 게 없잖아.","JPN":"演技って台本どおりにやらなきゃいけなくて、アタシの意のままにはできないじゃないか。","ENG":"Acting’s all based on the script. There’s no room for freedom.","TWN":"演戲就只能照劇本演，又不能隨我開心。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"그런 시시한 건 저 여자나 하라고 해.","JPN":"そんなくだらないもの、あの女にさせろ。","ENG":"That woman can do all the boring stuff.","TWN":"這麼無聊的事你還是找那女的吧！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"네가 양보를 하다니 별일이구나.","JPN":"其方が譲るとは、珍しいのう。","ENG":"It’s surprising to see you give up.","TWN":"你竟然會退讓，真是稀奇。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"결투라면 사족을 못 쓰는 녀석이 말이지.","JPN":"決闘には目がないのに。","ENG":"I thought you were obsessed with duels.","TWN":"說到決鬥你不是當仁不讓的嗎？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"결투? 연기랑 그거랑 뭔 상관인데?","JPN":"決闘？　演技と何の関係があるんだ？","ENG":"Duels? What does that have to do with acting?","TWN":"決鬥？演戲和決鬥有什麼關係？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"세상에는 무식하게 힘자랑만 하는 결투만 있는 게 아니란다.","JPN":"世の中には、力比べの決闘だけがあるわけではあるまい。","ENG":"Not all duels in the world consist of boasting one’s strength.","TWN":"所謂的決鬥，並不是只有比蠻力而已。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"상대와 우열을 가릴 수 있다면 그게 무엇이든 결투가 될 수 있지.","JPN":"相手と優劣を競えられるのなら、それが何であろうと決闘になり得る。","ENG":"Anything can become a duel if you can determine your superiority.","TWN":"只要能和對方分出高下的都算是決鬥。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"감독이 저렇게까지 권하는데 거절한다는 건, 저 여자에게 패배를 인정하는 셈이나 다름 없지 않겠느냐?","JPN":"監督があそこまで勧誘しているのに拒絶するということは、あの女に敗北したと認めるも同然ではないか？","ENG":"You’re refusing the director’s offer though he’s pleading with you to do it. Wouldn’t that be seen as a defeat to the client?","TWN":"導演都已經力勸到這種程度，你還是堅持拒絕，那就表示你承認你輸給那女的不是嗎？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"…흥, 내가 저런 약골에게 패배? 누구 맘대로?!","JPN":"……フン、アタシがあんな弱いやつに負ける？　ふざけるな！！","ENG":"...Who says I lose to that weakling? Who says that?!","TWN":"…哼！我會輸給那種嬌嬌女？誰說的！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"좋아. 까짓 거 해보자고. 이기면 돈도 주는 거지?","JPN":"よし。やってやろうじゃないか。勝ったら金もくれるんだろ？","ENG":"All right, let’s do this. I get the money if I win, right?","TWN":"好啊！演就演！我贏的話有錢拿吧？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"아앗! 진심으로 하는 말이예요? 당신들은 날 도와주기로 했잖아요!","JPN":"ああっ！　本気で言ってるんですか？　あなたたち、私に協力してくれるんじゃなかったんですか！","ENG":"What! Are you serious? You’re all supposed to help me!","TWN":"欸欸！你是認真的嗎？你們不是應該幫我才對嗎！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그래서 원하는 대로 경쟁자를 모두 제거해줬잖아?","JPN":"だから望みどおりライバルをすべて排除してやったじゃろう？","ENG":"So we removed the opponents as you wanted.","TWN":"我們不是已經照著你的要求除掉其他競爭者嗎？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"애초에 연기에 자신이 있다면 고작 후보가 하나 늘어나는 걸로 불안할 것도 없지 않느냐?","JPN":"そもそも演技に自信があるなら、候補が1人増えたくらいで不安がる必要もあるまい。","ENG":"Why would you be so worried about one extra opponent if you’re confident in acting?","TWN":"你對你的演技有信心的話，就算多一個競爭對手，也沒什麼好怕的吧？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"윽… 그건…","JPN":"うっ……それは……","ENG":"Ugh... That’s...","TWN":"呃…我…"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"오오, 반가운 소식이군요. 그렇다면 지금 당장 본 촬영으로 넘어가서…!","JPN":"おお、受け入れてもらえるなら何よりだ。それなら、今すぐ本番に入って……！","ENG":"Oh, that’s great news. Then let’s get into...!","TWN":"真是太好啦！那我們就立刻進入正式拍攝…！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"다만.","JPN":"だが、","ENG":"But.","TWN":"且慢。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"이대로 결정을 지어버리면 시시하니, 다른 후보도 리허설에서 공정하게 연기할 기회는 줘야겠지?","JPN":"このまま決定づけるのもつまらないじゃろう。他の候補者にもリハーサルで公正に演技する機会を与えるべきじゃ。","ENG":"It’ll be boring if you just decide the lead like this. Shouldn’t you give all the candidates a chance to do the rehearsal?","TWN":"就這樣定案未免太無趣，應該要給其他人一個公平試鏡的機會吧？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"마, 맞아요!","JPN":"そ、そうです！","ENG":"That’s right!","TWN":"對…對啊！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"여기서 그렇게 갑자기 결정 정해버리면 지금까지 노력해온 내 입장은 뭐가 되는 데요?","JPN":"ここでそうやっていきなり決めてしまっては、今まで努力してきた私の立場はどうなるんですか？","ENG":"Isn't it so unfair that you decide on the lead actress all of a sudden?","TWN":"怎麼可以就這樣決定，那我從剛才到現在都在幹什麼？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"이건 정정당당하게 연기 실력으로 평가받아야 하는 자리잖아요!","JPN":"ここは正々堂々、演技の実力で評価する場でしょう！","ENG":"You’re supposed to be evaluated fairly based on acting skills here!","TWN":"這裡不是讓大家憑演技公平競爭的地方嗎！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"…쯧.","JPN":"……チッ。","ENG":"...Hmph.","TWN":"…嘖！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"계약이니 어쩔 수 없구만. 그럼 다음 촬영으로 넘어가지.","JPN":"契約だから仕方ない。じゃあ、次の撮影に入ろう。","ENG":"Well, a contract is a contract. Moving on to the next scene.","TWN":"有合約限制沒辦法，那就換下一場戲吧！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"크윽, 짜증나.","JPN":"うっ、腹立つ。","ENG":"Urgh, this is so annoying.","TWN":"唔唔，可惡！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"날 이렇게까지 구질구질하게 만들다니.","JPN":"私にこんなことまでさせるなんて。","ENG":"I didn’t want to be so pathetic like this.","TWN":"竟敢這樣耍我，"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"이번 리허설만 끝나면 저 감독 먼저 갈아치워 버리고 말겠어.","JPN":"このリハーサルさえ終わったら、あの監督から降板させてやる。","ENG":"I’m going to get rid of that director right after the rehearsal is finished.","TWN":"等我排演完就把那個導演一腳踢開！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};